ALTER TYPE "DesignRevisionStatus" ADD VALUE 'PENDING_CHECK' BEFORE 'PENDING_APPROVAL';
ALTER TYPE "DesignRevisionStatus" ADD VALUE 'CHECKED' BEFORE 'PENDING_APPROVAL';
CREATE TYPE "DesignRequirementCategory" AS ENUM ('CUSTOMER','FUNCTIONAL','PERFORMANCE','INTERFACE','MATERIAL','SAFETY','REGULATORY','MANUFACTURING','INSPECTION','OTHER');
CREATE TYPE "DesignVerificationMethod" AS ENUM ('CALCULATION','SIMULATION','DRAWING_REVIEW','INSPECTION','TEST','PROTOTYPE','COMPARISON','CUSTOMER_REVIEW');
CREATE TYPE "DesignRequirementStatus" AS ENUM ('OPEN','VERIFIED','FAILED','NOT_APPLICABLE');
CREATE TYPE "DesignMilestoneStatus" AS ENUM ('PLANNED','IN_PROGRESS','COMPLETED','DELAYED','CANCELLED');
CREATE TYPE "DesignCustomerApprovalStatus" AS ENUM ('PENDING','APPROVED','REJECTED');
ALTER TABLE "design_document_revisions" ADD COLUMN "checkedById" TEXT, ADD COLUMN "checkedAt" TIMESTAMP(3), ADD COLUMN "checkerNameSnapshot" TEXT, ADD COLUMN "checkNote" TEXT, ADD COLUMN "customerApprovalRequired" BOOLEAN NOT NULL DEFAULT false;
CREATE TABLE "design_requirements" ("id" TEXT NOT NULL,"projectId" TEXT NOT NULL,"requirementNumber" TEXT NOT NULL,"category" "DesignRequirementCategory" NOT NULL,"description" TEXT NOT NULL,"source" TEXT,"acceptanceCriteria" TEXT NOT NULL,"verificationMethod" "DesignVerificationMethod" NOT NULL,"required" BOOLEAN NOT NULL DEFAULT true,"status" "DesignRequirementStatus" NOT NULL DEFAULT 'OPEN',"verificationResult" TEXT,"evidence" JSONB,"verifiedById" TEXT,"verifiedAt" TIMESTAMP(3),"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "design_requirements_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "design_requirements_projectId_requirementNumber_key" ON "design_requirements"("projectId","requirementNumber");CREATE INDEX "design_requirements_projectId_status_idx" ON "design_requirements"("projectId","status");
CREATE TABLE "design_milestones" ("id" TEXT NOT NULL,"projectId" TEXT NOT NULL,"title" TEXT NOT NULL,"description" TEXT,"ownerId" TEXT NOT NULL,"dueDate" TIMESTAMP(3) NOT NULL,"status" "DesignMilestoneStatus" NOT NULL DEFAULT 'PLANNED',"completedById" TEXT,"completedAt" TIMESTAMP(3),"evidence" JSONB,"createdById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "design_milestones_pkey" PRIMARY KEY ("id"));
CREATE INDEX "design_milestones_projectId_status_dueDate_idx" ON "design_milestones"("projectId","status","dueDate");CREATE INDEX "design_milestones_ownerId_status_idx" ON "design_milestones"("ownerId","status");
CREATE TABLE "design_customer_approvals" ("id" TEXT NOT NULL,"revisionId" TEXT NOT NULL,"status" "DesignCustomerApprovalStatus" NOT NULL DEFAULT 'PENDING',"customerApproverName" TEXT NOT NULL,"designation" TEXT,"organisation" TEXT,"approvalReference" TEXT,"evidence" JSONB,"comments" TEXT,"approvedAt" TIMESTAMP(3),"recordedById" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "design_customer_approvals_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "design_customer_approvals_revisionId_key" ON "design_customer_approvals"("revisionId");CREATE INDEX "design_customer_approvals_status_createdAt_idx" ON "design_customer_approvals"("status","createdAt");
ALTER TABLE "design_requirements" ADD CONSTRAINT "design_requirements_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "design_projects"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "design_milestones" ADD CONSTRAINT "design_milestones_projectId_fkey" FOREIGN KEY ("projectId") REFERENCES "design_projects"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "design_customer_approvals" ADD CONSTRAINT "design_customer_approvals_revisionId_fkey" FOREIGN KEY ("revisionId") REFERENCES "design_document_revisions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
